parameters.jsCode:
const projectsMeta = $('Percentages of budget spent').all().map(p=>p.json)

console.log(projectsMeta)

for (const item of $input.all()) {
  item.json.computed = {};
  item.json.computed.timeWorkedInSeconds = item.json.time_entries.reduce(
    (acc, curr) => {
      console.log(curr);
      return acc + curr.timeSpentInSeconds;
    },
    0,
  );
  const normalizedTimeOffRequests = item.json.timeOffRequests
    .map((req) => ({
      ...req,
      startDate: req.startDate.slice(0, 10),
      endDate: req.endDate.slice(0, 10),
    }))
    .map(({ startDate, endDate, ...req }) => [
      { ...req, date: startDate },
      { ...req, date: endDate },
    ])
    .flat();
  console.log(normalizedTimeOffRequests);
  item.json.computed.workScheduleInSecondsWithoutTimeOffRequests =
    item.json.workSchedule
      .filter((workScheduleItem) => workScheduleItem.isWorking)
      .reduce((acc, curr) => {
        if (normalizedTimeOffRequests.includes((req) => req.date === curr.date))
          return 0;
        return acc + (curr?.hours ?? 0);
      }, 0) *
    60 *
    60;
  item.json.computed.timeBehindScheduleInSeconds =
    item.json.computed.workScheduleInSecondsWithoutTimeOffRequests -
    item.json.computed.timeWorkedInSeconds;
  item.json.computed.timeBehindScheduleHours = Math.floor(
    Math.abs(item.json.computed.timeBehindScheduleInSeconds) / 3600,
  );
  item.json.computed.timeBehindScheduleMinutes = Math.floor(
    (Math.abs(item.json.computed.timeBehindScheduleInSeconds) % 3600) / 60,
  );
  item.json.computed.percentageBehindSchedule =
    (item.json.computed.timeBehindScheduleInSeconds /
      item.json.computed.workScheduleInSecondsWithoutTimeOffRequests) *
    100;
  const getSeconds = (start, end) => (new Date(end) - new Date(start)) / 1000;
  const projectMap = {};

  item.json.time_entries.forEach((entry) => {
    const projectId = entry.project.id;

    if (!projectMap[projectId]) {
      projectMap[projectId] = {
        ...entry.project,
        timeSpentInSeconds: 0,
        timeEntries: {},
      };
    }

    const project = projectMap[projectId];
    const duration = getSeconds(entry.startTime, entry.endTime);

    const taskKey = entry.task ? `task-${entry.task.id}` : `note-${entry.note}`;

    if (!project.timeEntries[taskKey]) {
      project.timeEntries[taskKey] = {
        note: entry.note,
        ...(entry.task && { task: entry.task }),
        tags: entry.tags,
        isBillable: entry.isBillable,
        isInvoiced: entry.isInvoiced,
        startTime: entry.startTime,
        endTime: entry.endTime,
        timeSpentInSeconds: 0,
      };
    }

    project.timeSpentInSeconds += duration;
    project.timeEntries[taskKey].timeSpentInSeconds += duration;

    if (
      new Date(entry.endTime) > new Date(project.timeEntries[taskKey].endTime)
    ) {
      project.timeEntries[taskKey].endTime = entry.endTime;
    }
  });

  const result = Object.values(projectMap).map((project) => {
    return {
      project: {
        ...project,
        budgetSpentPercentages: projectsMeta.find(p=>p.id === project.id)?.budget.spentPercentages ?? '[???]',
        timeEntries: Object.values(project.timeEntries),
      },
    };
  });
  item.json.computed.projects = result;
}

return $input.all();
